"use client";

import { useEffect, useRef, useState } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";

import {
  Search,
  ShoppingBag,
  User,
  Menu,
  X,
  Store,
  ChevronDown,
  MessageCircle,
  MapPin,
} from "lucide-react";

import { getCategories } from "../apis/category/category";
import { sendWhatsAppOtp } from "../apis/whatsapp/whatsapp";

export default function Navbar() {
  const router = useRouter();
  const pathname = usePathname();

  const profileDropdownRef = useRef(null);
  const categoryPreviewTimeoutRef = useRef(null);

  const [searchQuery, setSearchQuery] = useState("");
  const [categories, setCategories] = useState([]);

  const [customer, setCustomer] = useState(null);
  const [cartCount, setCartCount] = useState(0);

  const [profileDropdownOpen, setProfileDropdownOpen] = useState(false);
  const [userModalOpen, setUserModalOpen] = useState(false);
  const [allMenuOpen, setAllMenuOpen] = useState(false);

  const [activeCategoryId, setActiveCategoryId] = useState(null);
  const [previewCategoryId, setPreviewCategoryId] = useState(null);
  const [searchCategory, setSearchCategory] = useState("All");

  const [whatsappOtpLoading, setWhatsappOtpLoading] = useState(false);

  const isActive = (path) => pathname === path;

  useEffect(() => {
    getAllCategories();
    getCustomerFromStorage();
    getCartCountFromStorage();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (
        profileDropdownRef.current &&
        !profileDropdownRef.current.contains(event.target)
      ) {
        setProfileDropdownOpen(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      clearTimeout(categoryPreviewTimeoutRef.current);
    };
  }, []);

  const getAllCategories = async () => {
    try {
      const response = await getCategories();

      const list = Array.isArray(response?.data?.data)
        ? response.data.data
        : Array.isArray(response?.data)
        ? response.data
        : Array.isArray(response)
        ? response
        : [];

      setCategories(list);
    } catch (error) {
      console.error("Category API error:", error);

      setCategories([
        { _id: "for-you", name: "For You" },
        { _id: "fashion", name: "Fashion" },
        { _id: "mobiles", name: "Mobiles" },
        { _id: "beauty", name: "Beauty" },
        { _id: "electronics", name: "Electronics" },
        { _id: "home", name: "Home" },
        { _id: "appliances", name: "Appliances" },
        { _id: "toys", name: "Toys" },
        { _id: "food", name: "Food" },
        { _id: "auto", name: "Auto" },
        { _id: "sports", name: "Sports" },
        { _id: "books", name: "Books" },
        { _id: "furniture", name: "Furniture" },
      ]);
    }
  };

  const getCustomerFromStorage = () => {
    try {
      const savedCustomer =
        localStorage.getItem("customer") ||
        localStorage.getItem("customerData") ||
        localStorage.getItem("user");

      if (savedCustomer) {
        setCustomer(JSON.parse(savedCustomer));
      }
    } catch (error) {
      console.error("Customer localStorage error:", error);
    }
  };

  const getCartCountFromStorage = () => {
    try {
      const savedCart = localStorage.getItem("cart");

      if (savedCart) {
        const cartItems = JSON.parse(savedCart);
        setCartCount(Array.isArray(cartItems) ? cartItems.length : 0);
      }
    } catch (error) {
      console.error("Cart localStorage error:", error);
    }
  };

  const handleSearchSubmit = (event) => {
    event.preventDefault();

    const query = searchQuery.trim();

    if (!query) return;

    router.push(`/shop?search=${encodeURIComponent(query)}`);
  };

  const handleLogout = () => {
    localStorage.removeItem("customer");
    localStorage.removeItem("customerData");
    localStorage.removeItem("user");
    localStorage.removeItem("token");

    setCustomer(null);
    setProfileDropdownOpen(false);

    router.push("/");
  };

  const openVendorModal = () => {
    router.push("/vendor-register");
  };

  const sendOtp = async () => {
    try {
      const number = customer?.number || customer?.phone;

      if (!number) {
        alert("Please login first.");
        setUserModalOpen(true);
        return;
      }

      setWhatsappOtpLoading(true);

      await sendWhatsAppOtp({ number });

      alert("WhatsApp OTP sent successfully.");
    } catch (error) {
      console.error("WhatsApp OTP error:", error);
      alert("WhatsApp OTP send failed.");
    } finally {
      setWhatsappOtpLoading(false);
    }
  };

  const handleCategoryPreview = (categoryId) => {
    clearTimeout(categoryPreviewTimeoutRef.current);
    setPreviewCategoryId(categoryId);
  };

  const clearCategoryPreview = () => {
    categoryPreviewTimeoutRef.current = setTimeout(() => {
      setPreviewCategoryId(null);
    }, 200);
  };

  return (
    <>
      <header className="sticky top-0 z-50 bg-white border-b border-gray-200 shadow-sm">
        {/* PART 1 */}
        <div className="bg-white border-b border-gray-100">
          <div className="max-w-[1450px] mx-auto px-4 sm:px-6 lg:px-10">
            <div className="h-[52px] flex items-center justify-between gap-4">
              <Link
                href="/"
                className="inline-flex items-center gap-2 px-5 py-2 rounded-xl bg-[#FF9900] text-white font-black text-xl tracking-tight shadow-sm hover:bg-[#e68a00] transition-colors"
              >
                Jajot
              </Link>

              <button
                type="button"
                className="hidden sm:flex items-center gap-1.5 text-sm font-semibold text-gray-900 hover:text-[#FF9900] transition-colors"
              >
                <MapPin size={18} />
                <span>Location not set</span>
                <span className="font-bold underline underline-offset-2 text-[#FF9900]">
                  Select delivery location
                </span>
              </button>
            </div>
          </div>
        </div>

        {/* PART 2 */}
        <div className="bg-white">
          <div className="max-w-[1450px] mx-auto px-4 sm:px-6 lg:px-10">
            <div className="min-h-[64px] flex items-center justify-between gap-4">
              <button
                type="button"
                onClick={() => setAllMenuOpen(true)}
                className="md:hidden w-10 h-10 rounded-xl flex items-center justify-center border border-gray-200 text-gray-800 hover:border-[#FF9900] hover:text-[#FF9900] transition-colors"
              >
                <Menu size={20} />
              </button>

              <form
                onSubmit={handleSearchSubmit}
                className="flex h-11 w-full max-w-[560px] overflow-hidden rounded-xl border-2 border-[#FF9900] bg-white transition-all duration-200 focus-within:ring-2 focus-within:ring-[#FF9900]/20"
              >
                <button
                  type="submit"
                  className="flex w-12 shrink-0 items-center justify-center bg-white text-gray-600 hover:text-[#FF9900] transition"
                  aria-label="Search"
                >
                  <Search size={21} />
                </button>

                <input
                  value={searchQuery}
                  onChange={(event) => setSearchQuery(event.target.value)}
                  placeholder="Search for Products, Brands and More"
                  className="min-w-0 flex-1 bg-white px-2 text-[15px] font-medium text-gray-900 outline-none placeholder:font-normal placeholder:text-gray-500"
                />
              </form>

              <div className="flex items-center gap-2 sm:gap-4">
                <div className="relative" ref={profileDropdownRef}>
                  <button
                    type="button"
                    onClick={() =>
                      customer
                        ? setProfileDropdownOpen((prev) => !prev)
                        : setUserModalOpen(true)
                    }
                    className="flex items-center gap-1.5 h-10 px-2 sm:px-3 rounded-lg text-sm font-semibold text-gray-900 hover:text-[#FF9900] hover:bg-[#FF9900]/10 transition-colors"
                  >
                    <User size={20} />
                    <span className="hidden sm:inline">
                      {customer
                        ? customer.name?.split(" ")[0] || "Account"
                        : "Login"}
                    </span>

                    <ChevronDown
                      size={15}
                      className={`transition-transform ${
                        profileDropdownOpen ? "rotate-180" : ""
                      }`}
                    />
                  </button>

                  {customer && profileDropdownOpen && (
                    <div className="absolute right-0 top-full mt-2 w-60 bg-white rounded-xl shadow-2xl border border-gray-100 z-[9999] overflow-hidden">
                      <div className="px-4 py-3 border-b border-gray-100">
                        <p className="font-bold text-gray-900 text-sm">
                          Hello {customer.name || "there"}
                        </p>

                        {customer.number && (
                          <p className="text-xs text-gray-500 mt-0.5">
                            {customer.number}
                          </p>
                        )}
                      </div>

                      <div className="py-1">
                        <Link
                          href="/orders"
                          onClick={() => setProfileDropdownOpen(false)}
                          className="block px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900]"
                        >
                          Orders
                        </Link>

                        <Link
                          href="/Wishlist"
                          onClick={() => setProfileDropdownOpen(false)}
                          className="block px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900]"
                        >
                          Wishlist
                        </Link>

                        <Link
                          href="/contact"
                          onClick={() => setProfileDropdownOpen(false)}
                          className="block px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900]"
                        >
                          Contact Us
                        </Link>
                      </div>

                      <div className="border-t border-gray-100 py-1">
                        <button
                          type="button"
                          onClick={handleLogout}
                          className="w-full text-left px-4 py-2.5 text-sm text-red-600 hover:bg-red-50"
                        >
                          Logout
                        </button>
                      </div>
                    </div>
                  )}
                </div>

                <div className="relative hidden md:block group">
                  <button
                    type="button"
                    className="flex items-center gap-1.5 h-10 px-3 rounded-lg text-sm font-semibold text-gray-900 hover:text-[#FF9900] hover:bg-[#FF9900]/10"
                  >
                    More
                    <ChevronDown
                      size={15}
                      className="group-hover:rotate-180 transition-transform"
                    />
                  </button>

                  <div className="absolute right-0 top-full pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-[9999]">
                    <div className="w-56 bg-white rounded-xl shadow-2xl border border-gray-100 overflow-hidden py-1">
                      <button
                        type="button"
                        onClick={openVendorModal}
                        className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900]"
                      >
                        <Store size={16} /> Become a Vendor
                      </button>

                      <button
                        type="button"
                        onClick={sendOtp}
                        disabled={whatsappOtpLoading}
                        className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-emerald-600 disabled:opacity-60"
                      >
                        <MessageCircle size={16} />
                        {whatsappOtpLoading ? "Sending..." : "WhatsApp OTP"}
                      </button>
                    </div>
                  </div>
                </div>

                <Link
                  href="/Addtocard"
                  className="relative flex items-center gap-1.5 h-10 px-2 sm:px-3 rounded-lg text-gray-900 hover:text-[#FF9900] hover:bg-[#FF9900]/10 font-semibold text-sm"
                >
                  <ShoppingBag size={21} />
                  <span className="hidden sm:inline">Cart</span>

                  {cartCount > 0 && (
                    <span className="absolute -top-1 -right-1 w-4 h-4 rounded-full bg-[#FF9900] text-black text-[10px] font-bold flex items-center justify-center">
                      {cartCount}
                    </span>
                  )}
                </Link>
              </div>
            </div>
          </div>
        </div>

        {/* PART 3 */}
        <div className="bg-white/95 backdrop-blur-md border-t border-gray-100">
          <div className="max-w-[1450px] mx-auto px-4 sm:px-6 lg:px-10">
            <div
              className="hidden md:flex min-h-[62px] items-center gap-1 overflow-x-auto scrollbar-hide"
              onMouseEnter={() =>
                clearTimeout(categoryPreviewTimeoutRef.current)
              }
              onMouseLeave={clearCategoryPreview}
            >
              <button
                type="button"
                onClick={() => setAllMenuOpen(true)}
                className="flex flex-col items-center justify-center gap-1 px-4 py-1.5 shrink-0 text-gray-800 hover:text-[#FF9900]"
              >
                <Menu size={22} />
                <span className="text-xs font-semibold whitespace-nowrap">
                  All
                </span>
              </button>

              <Link
                href="/"
                onClick={() => {
                  setActiveCategoryId(null);
                  setPreviewCategoryId(null);
                  setSearchCategory("All");
                }}
                className={`flex flex-col items-center justify-center gap-1 px-4 py-1.5 shrink-0 ${
                  isActive("/")
                    ? "text-[#FF9900]"
                    : "text-gray-800 hover:text-[#FF9900]"
                }`}
              >
                <Store size={22} />
                <span
                  className={`text-xs whitespace-nowrap ${
                    isActive("/")
                      ? "font-bold border-b-2 border-[#FF9900] pb-1"
                      : "font-semibold"
                  }`}
                >
                  Home
                </span>
              </Link>

              {categories.slice(0, 12).map((cat) => (
                <Link
                  key={cat._id}
                  href={`/shop?category=${encodeURIComponent(cat.name)}`}
                  onMouseEnter={() => handleCategoryPreview(cat._id)}
                  onFocus={() => handleCategoryPreview(cat._id)}
                  onClick={() => {
                    setActiveCategoryId(cat._id);
                    setPreviewCategoryId(cat._id);
                    setSearchCategory(cat.name);
                  }}
                  className={`flex flex-col items-center justify-center gap-1 px-4 py-1.5 shrink-0 ${
                    activeCategoryId === cat._id
                      ? "text-[#FF9900]"
                      : "text-gray-800 hover:text-[#FF9900]"
                  }`}
                >
                  <ShoppingBag size={22} />

                  <span
                    className={`text-xs whitespace-nowrap ${
                      activeCategoryId === cat._id
                        ? "font-bold border-b-2 border-[#FF9900] pb-1"
                        : "font-semibold"
                    }`}
                  >
                    {cat.name}
                  </span>
                </Link>
              ))}
            </div>
          </div>
        </div>
      </header>

      {allMenuOpen && (
        <div className="fixed inset-0 z-[99999] bg-black/50">
          <div className="w-[290px] max-w-[85%] h-full bg-white shadow-2xl p-4">
            <div className="flex items-center justify-between border-b pb-3">
              <h2 className="text-lg font-bold text-gray-900">
                All Categories
              </h2>

              <button
                type="button"
                onClick={() => setAllMenuOpen(false)}
                className="text-gray-500 hover:text-gray-900"
              >
                <X size={22} />
              </button>
            </div>

            <div className="py-3">
              {categories.map((cat) => (
                <Link
                  key={cat._id}
                  href={`/shop?category=${encodeURIComponent(cat.name)}`}
                  onClick={() => {
                    setActiveCategoryId(cat._id);
                    setSearchCategory(cat.name);
                    setAllMenuOpen(false);
                  }}
                  className="block px-3 py-2.5 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-100 hover:text-[#FF9900]"
                >
                  {cat.name}
                </Link>
              ))}
            </div>
          </div>
        </div>
      )}

      {userModalOpen && (
        <div className="fixed inset-0 z-[99999] bg-black/50 flex items-center justify-center px-4">
          <div className="bg-white rounded-xl w-full max-w-md p-5 relative">
            <button
              type="button"
              onClick={() => setUserModalOpen(false)}
              className="absolute right-4 top-4 text-gray-500 hover:text-black"
            >
              <X size={22} />
            </button>

            <h2 className="text-xl font-bold text-gray-900 mb-2">Login</h2>

            <p className="text-sm text-gray-500 mb-4">
              Click the button below to log in.
            </p>

            <button
              type="button"
              onClick={() => {
                setUserModalOpen(false);
                router.push("/login");
              }}
              className="w-full bg-[#FF9900] text-black font-bold py-2 rounded-lg hover:bg-[#e68a00]"
            >
              Go to Login
            </button>
          </div>
        </div>
      )}
    </>
  );
}
